const fmt = n => 'NT$ ' + Math.round(Number(n || 0)).toLocaleString('zh-TW');
let siteData = null;
function getPrefix(){ return location.pathname.includes('/stores/') ? '../' : ''; }
async function loadData(){
  if(siteData) return siteData;
  const prefix = getPrefix();
  try{
    const res = await fetch(prefix + 'data.json', {cache:'no-store'});
    if(!res.ok) throw new Error('data load failed');
    siteData = await res.json();
  }catch(err){
    siteData = FALLBACK_DATA;
  }
  return siteData;
}
function setupMenu(){
  const btn = document.querySelector('[data-menu-toggle]');
  const nav = document.querySelector('[data-nav]');
  if(btn && nav){ btn.addEventListener('click',()=>nav.classList.toggle('open')); }
}
